/* --- Handler: builtin functions (SIZE, SUBSTR, CHAR) --- */
EXEC_BUILTIN: PROC;
    SELECT;
        WHEN (X_OP = OP_SIZE) DO;
            DCL SZ_OFF INT;
            DCL SZ_LEN INT;
            DCL SZ_P PTR;
            ESP = ESP - 1;
            SZ_OFF = ESTK(ESP);
            SZ_P = ADDR(SB) + SZ_OFF;
            SZ_LEN = 0;
            DO WHILE (SZ_P->DTAG != 0);
                SZ_LEN = SZ_LEN + 1;
                SZ_P = ADDR(SB) + SZ_OFF + SZ_LEN;
            END;
            ESTK(ESP) = SZ_LEN;
            ETYP(ESP) = VTYP_INT;
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP_INT;
        END;
        WHEN (X_OP = OP_SUBSTR) DO;
            DCL SS_STR INT;
            DCL SS_POS INT;
            DCL SS_LEN INT;
            DCL SS_SLN INT;
            DCL SS_I INT;
            DCL SS_P PTR;
            DCL SS_DP PTR;
            DCL SS_DST INT;
            ESP = ESP - 1;
            SS_LEN = ESTK(ESP);
            ESP = ESP - 1;
            SS_POS = ESTK(ESP);
            ESP = ESP - 1;
            SS_STR = ESTK(ESP);
            SS_P = ADDR(SB) + SS_STR;
            SS_SLN = 0;
            DO WHILE (SS_P->DTAG != 0);
                SS_SLN = SS_SLN + 1;
                SS_P = ADDR(SB) + SS_STR + SS_SLN;
            END;
            SS_DST = SBPOS;
            IF (SS_POS < 1) THEN SS_POS = 1;
            IF (SS_POS > SS_SLN) THEN SS_POS = SS_SLN + 1;
            SS_I = 0;
            DO WHILE (SS_I < SS_LEN AND (SS_POS + SS_I - 1) < SS_SLN);
                SS_P = ADDR(SB) + SS_STR + SS_POS + SS_I - 1;
                SS_DP = ADDR(SB) + SBPOS;
                SS_DP->DTAG = SS_P->DTAG;
                SBPOS = SBPOS + 1;
                SS_I = SS_I + 1;
            END;
            SS_DP = ADDR(SB) + SBPOS;
            SS_DP->DTAG = 0;
            SBPOS = SBPOS + 1;
            ESTK(ESP) = SS_DST;
            ETYP(ESP) = VTYP_STR;
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP_STR;
        END;
        WHEN (X_OP = OP_CHAR) DO;
            DCL CH_CODE INT;
            DCL CH_DST INT;
            DCL CH_DP PTR;
            ESP = ESP - 1;
            CH_CODE = ESTK(ESP);
            CH_DST = SBPOS;
            CH_DP = ADDR(SB) + SBPOS;
            CH_DP->DTAG = CH_CODE;
            SBPOS = SBPOS + 1;
            CH_DP = ADDR(SB) + SBPOS;
            CH_DP->DTAG = 0;
            SBPOS = SBPOS + 1;
            ESTK(ESP) = CH_DST;
            ETYP(ESP) = VTYP_STR;
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP_STR;
        END;
        WHEN (X_OP = OP_DUMP) DO;

